INSERT INTO `wp_posts` VALUES (442,1,'2026-03-09 20:05:08','2026-03-09 20:05:08','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Page Title</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"width\":\"66.66%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:66.66%\"><!-- wp:image {\"id\":437,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:10003/wp-content/uploads/2026/03/jumana-mannas-800-kvm-store-verk-substitue-legges-i-det-nye-regjeringskvartalet-i-oslo.-foto-pal-weiby-statsbygg-scaled-1-1024x768.jpg\" alt=\"\" class=\"wp-image-437\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"33.33%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:33.33%\"><!-- wp:paragraph -->\n<p>Verket, som har fått arbeidstittelen <em>Substitute</em>*, måler 800 kvadratmeter, og består av steiner donert fra kommuner og andre aktører i hele Norge. Her er storgatestein fra Stavanger, stein fra bybrua i Drammen, <a href=\"https://www.jevnaker.kommune.no/ti-tonn-jevnaker-stein-til-det-nye-regjeringskvartalet.6611921-505248.html\" target=\"_blank\" rel=\"noreferrer noopener\">sprengstein fra Svenådalen</a>og <a href=\"https://namsos.kommune.no/aktuelt/fra-kirke-til-mur-til-kunst.28698.aspx\" target=\"_blank\" rel=\"noreferrer noopener\">stein fra den bombede gammelkirka i Namsos</a>. Noen steiner har reist helt fra Kautokeino, og verket består også av en liten inngravert kleberstein fra Nidarosdomen i Trondheim.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"width\":\"33.33%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:33.33%\"><!-- wp:paragraph -->\n<p>For å lage verket må tusenvis av kilo med stein flyttes med stor presisjon – et arbeid Manna ikke gjør alene. Med seg har hun erfarne håndverkere fra Agaia, som er totalleverandør av uteområdet i det nye regjeringskvartalet.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ifølge prosjektleder Fridtjof Myhrene har Agaia hatt mellom tre og seks arbeidere i Lier for å håndtere og montere alle de individuelle steinene siden de startet arbeidet med Mannas verk for snart et halvt år siden.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"66.66%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:66.66%\"><!-- wp:image {\"id\":440,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:10003/wp-content/uploads/2026/03/jumana-manna_substitute_photo-niklas-hart-9-2048x1366-1-1024x683.jpg\" alt=\"\" class=\"wp-image-440\"/><figcaption class=\"wp-element-caption\">Jumana Manna. Artwork: substitute. Til bygulvet i Regjeringskvartalet, finansert av KORO.</figcaption></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:image {\"id\":439,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:10003/wp-content/uploads/2026/03/drone_large-1024x581.jpg\" alt=\"\" class=\"wp-image-439\"/></figure>\n<!-- /wp:image -->','Om Prosjektet','','inherit','closed','closed','','412-revision-v1','','','2026-03-09 20:05:08','2026-03-09 20:05:08','',412,'http://localhost:10003/?p=442',0,'revision','',0);
